          "locality": "Mountain View",
          "enableUspsCass": true
        }
      },
      "expected_output": "method=POST\nstatus=200\nurl=https://addressvalidation.googleapis.com/v1:validateAddress?key=AIzaSyD_sJl0qMA65CYHMBokVfMNA7AKyt5ERYs\njson={\"address\":{\"addressLines\":\"1600 Amphitheatre Pk\",\"locality\":\"Mountain View\",\"regionCode\":\"US\"},\"enableUspsCass\":true}\nresponse_address_lines=1600 Amphitheatre Pkwy\n"
    }
  ]
}

Here are the public test cases for feature11_1_static_map_overlays:
{
  "description": "Static map marker and path overlays render style attributes followed by normalized locations in the pipe-separated wire format expected by map image requests.",
  "cases": [
    {
      "input": {
        "action": "map_marker_overlay",
        "locations": [
          {
            "lat": -33.867486,
            "lng": 151.20699
          },
          "Sydney"
        ],
        "size": "small",
        "color": "blue",
        "label": "S"
      },
      "expected_output": "marker=size:small|color:blue|label:S|-33.867486,151.20699|Sydney\n"
    }
  ]
}

Here are the public test cases for feature11_2_static_map_image_request:
{
  "description": "Static map image requests convert size, center, zoom, map type, format, scale, visibility, markers, and path overlays into a streamed image GET request.",
  "cases": [
    {
      "input": {
        "action": "static_map_request",
        "request": {
          "size": [
            400,
            400
          ],
          "zoom": 6,
          "center": [
            63.259591,
            -144.667969
          ],
          "maptype": "hybrid",
          "format": "png",
          "scale": 2,
          "visible": [
            "Tok,AK"
          ],
          "path": {
            "points": [
              [
                62.107733,
                -145.541936
              ],
              "Delta+Junction,AK"
            ],
            "weight": 5,
            "color": "red"
          },
          "markers": [
            {
              "locations": [
                [
                  62.107733,
                  -145.541936
                ]
              ],
              "color": "blue",
              "label": "S"
            },
            {
              "locations": [
                "Delta+Junction,AK"
              ],
              "size": "tiny",
              "color": "green"
            },
            {
              "locations": [
                "Tok,AK"
              ],
              "size": "mid",
              "color": "0xFFFF00",
              "label": "C"
            }
          ]
        }
      },
      "expected_output": "method=GET\nstatus=200\nurl=https://maps.googleapis.com/maps/api/staticmap?center=63.259591%2C-144.667969&format=png&key=AIzaasdf&maptype=hybrid&markers=color%3Ablue%7Clabel%3AS%7C62.107733%2C-145.541936&markers=size%3Amid%7Ccolor%3A0xFFFF00%7Clabel%3AC%7CTok%2CAK&markers=size%3Atiny%7Ccolor%3Agreen%7CDelta%2BJunction%2CAK&path=weight%3A5%7Ccolor%3Ared%7C62.107733%2C-145.541936%7CDelta%2BJunction%2CAK&scale=2&size=400x400&visible=Tok%2CAK&zoom=6\nresponse_stream=true\n"
    }
  ]
}

